SELECT ?team ?teamLabel (COUNT(*) AS ?count) WHERE {
  ?season wdt:P31 wd:Q25198620 ;
          wdt:P1201 wd:Q918 ;
          wdt:P12475 ?player ;
          wdt:P580 ?seasonStart ;
          wdt:P582 ?seasonEnd .

  ?player p:P463 ?membership .
  ?membership ps:P463 ?team ;
              pq:P580 ?memStart ;
              pq:P582 ?memEnd .

  FILTER (?memStart <= ?seasonEnd && ?memEnd >= ?seasonStart)
  OPTIONAL { ?team rdfs:label ?teamLabel . FILTER(LANG(?teamLabel) = "en") }
}
GROUP BY ?team ?teamLabel
ORDER BY DESC(?count)

